internal mutating func stablePartition(
  count n: Int,
  subrange: Range<Index>,
  by belongsInSecondPartition: (Element) throws -> Bool
) rethrows -> Index {
  if n == 0 { return subrange.lowerBound }
  if n == 1 {
    return try belongsInSecondPartition(self[subrange.lowerBound])
      ? subrange.lowerBound
      : subrange.upperBound
  }

  let h = n / 2
  let i = index(subrange.lowerBound, offsetBy: h)
  let j = try stablePartition(
    count: h,
    subrange: subrange.lowerBound..<i,
    by: belongsInSecondPartition)
  let k = try stablePartition(
    count: n - h,
    subrange: i..<subrange.upperBound,
    by: belongsInSecondPartition)
  return rotate(subrange: j..<k, toStartAt: i)
}

@inlinable
  public mutating func partition(
    subrange: Range<Index>,
    by belongsInSecondPartition: (Element) throws -> Bool
  ) rethrows -> Index {
    // This version of `partition(subrange:)` is half stable; the elements in
    // the first partition retain their original relative order.
    guard var i = try self[subrange].firstIndex(where: belongsInSecondPartition)
    else { return subrange.upperBound }

    var j = index(after: i)
    while j != subrange.upperBound {
      if try !belongsInSecondPartition(self[j]) {
        swapAt(i, j)
        formIndex(after: &i)
      }
      formIndex(after: &j)
    }

    return i
  }

public func chunked<Subject: Equatable>(
  on projection: (Element) throws -> Subject
) rethrows -> [(Subject, SubSequence)] {
  guard !isEmpty else { return [] }
  var result: [(Subject, SubSequence)] = []

  var start = startIndex
  var subject = try projection(self[start])

  for (index, element) in indexed().dropFirst() {
    let nextSubject = try projection(element)
    if subject != nextSubject {
      result.append((subject, self[start..<index]))
      start = index
      subject = nextSubject
    }
  }

  if start != endIndex {
    result.append((subject, self[start...]))
  }

  return result
}

internal func _minImplementation(
  count: Int,
  sortedBy areInIncreasingOrder: (Element, Element) throws -> Bool
) rethrows -> [Element] {
  var iterator = makeIterator()

  var result: [Element] = []
  result.reserveCapacity(count)
  while result.count < count, let e = iterator.next() {
    result.append(e)
  }
  try result.sort(by: areInIncreasingOrder)

  while let e = iterator.next() {
    // To be part of `result`, `e` must be strictly less than `result[count - 1]`.
    guard try areInIncreasingOrder(e, result[count - 1]) else { continue }
    result.removeLast()
    let insertionIndex =
      try result.partitioningIndex { try areInIncreasingOrder(e, $0) }
    result.insert(e, at: insertionIndex)
  }

  return result
}

func removeExpiredValues(referenceDate: Date) throws -> [URL] {
    let propertyKeys: [URLResourceKey] = [
        .isDirectoryKey,
        .contentModificationDateKey
    ]

    let urls = try allFileURLs(for: propertyKeys)
    let keys = Set(propertyKeys)
    let expiredFiles = urls.filter { fileURL in
        do {
            let meta = try FileMeta(fileURL: fileURL, resourceKeys: keys)
            if meta.isDirectory {
                return false
            }
            return meta.expired(referenceDate: referenceDate)
        } catch {
            return true
        }
    }
    try expiredFiles.forEach { url in
        try removeFile(at: url)
    }
    return expiredFiles
}

func split(whereSeparator separatorPredicate: (Element) -> Bool)
    -> [(grouping: [Element], trailingSeparator: Element?)]
  {
    guard !isEmpty else { return [] }

    var groupings = [(grouping: [Element], trailingSeparator: Element?)]()

    for element in self {
      if groupings.isEmpty || groupings.last?.trailingSeparator != nil {
        groupings.append((grouping: [], trailingSeparator: nil))
      }

      if separatorPredicate(element) {
        groupings[groupings.indices.last!].trailingSeparator = element
      } else {
        groupings[groupings.indices.last!].grouping.append(element)
      }
    }

    return groupings
  }

