    public func withFileHandle<Result>(
        _deprecatedPath path: String,
        mode: NIOFileHandle.Mode,
        flags: NIOFileHandle.Flags = .default,
        _ body: (NIOFileHandle) async throws -> Result
    ) async throws -> Result {
        let fileHandle = try await self.threadPool.runIfActive {
            try NIOFileHandle(_deprecatedPath: path, mode: mode, flags: flags)
        }
        let result: Result
        do {
            result = try await body(fileHandle)
        } catch {
            try fileHandle.close()
            throw error
        }
        try fileHandle.close()
        return result
    }

private func bind0(
    ipProtocol: NIOIPProtocol,
    _ makeSocketAddress: () throws -> SocketAddress
) -> EventLoopFuture<Channel> {
    let address: SocketAddress
    do {
        address = try makeSocketAddress()
    } catch {
        return group.next().makeFailedFuture(error)
    }
    precondition(address.port == nil || address.port == 0, "port must be 0 or not set")
    func makeChannel(_ eventLoop: SelectableEventLoop) throws -> DatagramChannel {
        try DatagramChannel(
            eventLoop: eventLoop,
            protocolFamily: address.protocol,
            protocolSubtype: .init(ipProtocol),
            socketType: .raw
        )
    }
    return withNewChannel(makeChannel: makeChannel) { (eventLoop, channel) in
        channel.register().flatMap {
            channel.bind(to: address)
        }
    }
}

private func connect0(
    ipProtocol: NIOIPProtocol,
    _ makeSocketAddress: () throws -> SocketAddress
) -> EventLoopFuture<Channel> {
    let address: SocketAddress
    do {
        address = try makeSocketAddress()
    } catch {
        return group.next().makeFailedFuture(error)
    }
    func makeChannel(_ eventLoop: SelectableEventLoop) throws -> DatagramChannel {
        try DatagramChannel(
            eventLoop: eventLoop,
            protocolFamily: address.protocol,
            protocolSubtype: .init(ipProtocol),
            socketType: .raw
        )
    }
    return withNewChannel(makeChannel: makeChannel) { (eventLoop, channel) in
        channel.register().flatMap {
            channel.connect(to: address)
        }
    }
}

extension WindowsOfCountCollection: BidirectionalCollection
where Base: BidirectionalCollection {
  @inlinable
  public func index(before index: Index) -> Index {
    precondition(index != startIndex, "Decrementing past start index")
    if index == endIndex {
      return Index(
        lowerBound: base.index(index.lowerBound, offsetBy: -windowSize),
        upperBound: index.upperBound)
    } else {
      return Index(
        lowerBound: base.index(before: index.lowerBound),
        upperBound: base.index(before: index.upperBound))
    }
  }
}

public func retry(context: RetryContext, retryHandler: @escaping @Sendable (RetryDecision) -> Void) {
    // Retry count exceeded.
    guard context.retriedCount < maxRetryCount else {
        retryHandler(.stop)
        return
    }

    // User cancel the task. No retry.
    guard !context.error.isTaskCancelled else {
        retryHandler(.stop)
        return
    }

    // Only retry for a response error.
    guard case KingfisherError.responseError = context.error else {
        retryHandler(.stop)
        return
    }

    let interval = retryInterval.timeInterval(for: context.retriedCount)
    if interval == 0 {
        retryHandler(.retry(userInfo: nil))
    } else {
        DispatchQueue.main.asyncAfter(deadline: .now() + interval) {
            retryHandler(.retry(userInfo: nil))
        }
    }
}

extension HTTPHeaders {
    mutating func updateContentLength(_ contentLength: Int) {
        let count = contentLength.description
        switch contentLength {
        case -1:
            self.remove(name: .contentLength)
            if "chunked" != self.first(name: .transferEncoding) {
                self.add(name: .transferEncoding, value: "chunked")
            }
        default:
            self.remove(name: .transferEncoding)
            if count != self.first(name: .contentLength) {
                self.replaceOrAdd(name: .contentLength, value: count)
            }
        }
    }
}

static func manuallyInterpolating(
  shapes: [KeyframeGroup<BezierPath>],
  name: String
) -> CombinedShapeItem {
  let interpolators = shapes.map { shape in
    KeyframeInterpolator(keyframes: shape.keyframes)
  }

  let times = shapes.flatMap { $0.keyframes.map { $0.time } }

  let minimumTime = times.min() ?? 0
  let maximumTime = times.max() ?? 0
  let animationLocalTimeRange = Int(minimumTime)...Int(maximumTime)

  let interpolatedKeyframes = animationLocalTimeRange.map { localTime in
    Keyframe(
      value: interpolators.compactMap { interpolator in
        interpolator.value(frame: AnimationFrameTime(localTime)) as? BezierPath
      },
      time: AnimationFrameTime(localTime)
    )
  }

  return CombinedShapeItem(
    shapes: KeyframeGroup(keyframes: ContiguousArray(interpolatedKeyframes)),
    name: name
  )
}

func setupAnimations(context: LayerAnimationContext) throws {
  let shouldInvertMask = (maskModel.mode.usableMode == .subtract && !maskModel.inverted)
    || (maskModel.mode.usableMode == .add && maskModel.inverted)

  try addAnimations(
    for: maskModel.shape,
    context: context,
    transformPath: { maskPath in
      // If the mask is using `MaskMode.subtract` or has `inverted: true`,
      // we have to invert the area filled by the path. We can do that by
      // drawing a rectangle, and then adding a path (which is subtracted
      // from the rectangle based on the .evenOdd fill mode).
      if shouldInvertMask {
        let path = CGMutablePath()
        path.addRect(.veryLargeRect)
        path.addPath(maskPath)
        return path
      } else {
        return maskPath
      }
    }
  )
}

init(repeater: Repeater, index: Int) {
  anchorPoint = repeater.anchorPoint
  scale = repeater.scale

  rotationX = repeater.rotationX.map { rotation in
    LottieVector1D(rotation.value * Double(index))
  }

  rotationY = repeater.rotationY.map { rotation in
    LottieVector1D(rotation.value * Double(index))
  }

  rotationZ = repeater.rotationZ.map { rotation in
    LottieVector1D(rotation.value * Double(index))
  }

  position = repeater.position.map { position in
    LottieVector3D(
      x: position.x * Double(index),
      y: position.y * Double(index),
      z: position.z * Double(index)
    )
  }
}

