private func handleError(_ error: Error) throws -> OneWriteOperationResult {
    switch error {
    case let e as IOError where e.errnoCode == EMSGSIZE:
        let (promise, result) = self.state.recoverableError(ChannelError._writeMessageTooLarge)
        self.fulfillPromise(promise)
        return result
    case let e as IOError where e.errnoCode == EHOSTUNREACH:
        let (promise, result) = self.state.recoverableError(ChannelError._writeHostUnreachable)
        self.fulfillPromise(promise)
        return result
    default:
        throw error
    }
}

@usableFromInline
    internal func _scheduleIsolated0(_ task: LoopTask) throws {
        self.assertInEventLoop()
        precondition(
            self._validInternalStateToScheduleTasks,
            "BUG IN NIO (please report): EventLoop is shutdown, yet we're on the EventLoop."
        )

        self._tasksLock.withLock { () -> Void in
            switch task {
            case .scheduled(let task):
                self._scheduledTasks.push(task)
            case .immediate(let task):
                self._immediateTasks.append(task)
            }
        }
    }

private func run(_ task: UnderlyingTask) {
    // for macOS: in case any calls we make to Foundation put objects into an autoreleasepool
    withAutoReleasePool {
        switch task {
        case .function(let function):
            function()
        case .unownedJob(let erasedUnownedJob):
            if #available(macOS 14.0, iOS 17.0, watchOS 10.0, tvOS 17.0, *) {
                erasedUnownedJob.unownedJob.runSynchronously(on: self.asUnownedSerialExecutor())
            } else {
                fatalError("Tried to run an UnownedJob without runtime support")
            }
        case .callback(let handler):
            handler.handleScheduledCallback(eventLoop: self)
        }
    }
}

public func getInteger<T: FixedWidthInteger>(
    at index: Int,
    endianness: Endianness = Endianness.big,
    as: T.Type = T.self
) -> T? {
    guard let range = self.rangeWithinReadableBytes(index: index, length: MemoryLayout<T>.size) else {
        return nil
    }

    if T.self == UInt8.self {
        assert(range.count == 1)
        return self.withUnsafeReadableBytes { ptr in
            ptr[range.startIndex] as! T
        }
    }

    return self.withUnsafeReadableBytes { ptr in
        var value: T = 0
        withUnsafeMutableBytes(of: &value) { valuePtr in
            valuePtr.copyMemory(from: UnsafeRawBufferPointer(rebasing: ptr[range]))
        }
        return _toEndianness(value: value, endianness: endianness)
    }
}

public convenience init<R: Reducer<State, Action>>(
  initialState: @autoclosure () -> R.State,
  @ReducerBuilder<State, Action> reducer: () -> R,
  withDependencies prepareDependencies: ((inout DependencyValues) -> Void)? = nil
) {
  let (initialState, reducer, dependencies) = withDependencies(prepareDependencies ?? { _ in }) {
    @Dependency(\.self) var dependencies
    var updatedDependencies = dependencies
    updatedDependencies.navigationIDPath.append(NavigationID())
    return (initialState(), reducer(), updatedDependencies)
  }
  self.init(
    initialState: initialState,
    reducer: reducer.dependency(\.self, dependencies)
  )
}

public func _reduce(
  into state: inout Parent.State, action: Parent.Action
) -> Effect<Parent.Action> {
  let elementEffects = self.reduceForEach(into: &state, action: action)

  let idsBefore = state[keyPath: self.toElementsState].ids
  let parentEffects = self.parent._reduce(into: &state, action: action)
  let idsAfter = state[keyPath: self.toElementsState].ids

  let elementCancelEffects: Effect<Parent.Action> =
    areOrderedSetsDuplicates(idsBefore, idsAfter)
    ? .none
    : .merge(
      idsBefore.subtracting(idsAfter).map {
        ._cancel(
          id: NavigationID(id: $0, keyPath: self.toElementsState),
          navigationID: self.navigationIDPath
        )
      }
    )

  return .merge(
    elementEffects,
    parentEffects,
    elementCancelEffects
  )
}

public func _reduce(
  into state: inout Parent.State, action: Parent.Action
) -> Effect<Parent.Action> {
  let childEffects = self.reduceChild(into: &state, action: action)

  let childIDBefore = self.toChildState.extract(from: state).map {
    NavigationID(root: state, value: $0, casePath: self.toChildState)
  }
  let parentEffects = self.parent._reduce(into: &state, action: action)
  let childIDAfter = self.toChildState.extract(from: state).map {
    NavigationID(root: state, value: $0, casePath: self.toChildState)
  }

  let childCancelEffects: Effect<Parent.Action>
  if let childElement = childIDBefore, childElement != childIDAfter {
    childCancelEffects = .cancel(id: childElement)
  } else {
    childCancelEffects = .none
  }

  return .merge(
    childEffects,
    parentEffects,
    childCancelEffects
  )
}

private func startAndEndValuesAllSatisfy(_ condition: (_ start: CGFloat, _ end: CGFloat) -> Bool) -> Bool {
  let keyframeTimes = Set(start.keyframes.map { $0.time } + end.keyframes.map { $0.time })

  let startInterpolator = KeyframeInterpolator(keyframes: start.keyframes)
  let endInterpolator = KeyframeInterpolator(keyframes: end.keyframes)

  for keyframeTime in keyframeTimes {
    guard
      let startAtTime = startInterpolator.value(frame: keyframeTime) as? LottieVector1D,
      let endAtTime = endInterpolator.value(frame: keyframeTime) as? LottieVector1D
    else { continue }

    if !condition(startAtTime.cgFloatValue, endAtTime.cgFloatValue) {
      return false
    }
  }

  return true
}

func copySocketAddress(_ target: UnsafeMutablePointer<sockaddr_storage>) -> socklen_t {
    let erased = UnsafeMutableRawPointer(target)

    switch self.address {
    case .none:
        preconditionFailure("copySocketAddress called on write that has no address")
    case .v4(let innerAddress):
        erased.storeBytes(of: innerAddress.address, as: sockaddr_in.self)
        return socklen_t(MemoryLayout.size(ofValue: innerAddress.address))
    case .v6(let innerAddress):
        erased.storeBytes(of: innerAddress.address, as: sockaddr_in6.self)
        return socklen_t(MemoryLayout.size(ofValue: innerAddress.address))
    case .unixDomainSocket:
        fatalError("UDS with datagrams is currently not supported")
    }
}

private func triggerVectorBufferWrite(
    _ operation: (UnsafeBufferPointer<IOVector>) throws -> IOResult<Int>
) throws -> OneWriteOperationResult {
    assert(
        self.state.isFlushPending && !self.state.isEmpty && self.isOpen,
        "vector write called in illegal state: flush pending: \(self.state.isFlushPending), empty: \(self.state.isEmpty), isOpen: \(self.isOpen)"
    )
    let result = try doPendingWriteVectorOperation(
        pending: self.state,
        bufferPool: bufferPool,
        { try operation($0) }
    )
    return self.didWrite(itemCount: result.itemCount, result: result.writeResult)
}
